// File: src/config.ts — typed environment configuration
interface AppConfig {
  port: number;
  databaseUrl: string;
  nodeEnv: 'development' | 'production' | 'test';
}
function loadConfig(): AppConfig {
  // process.env is populated by the deployment platform
  return {
    port: parseInt(process.env.PORT || '3000', 10),
    databaseUrl: process.env.DATABASE_URL || 'postgres://localhost:5432/app',
    nodeEnv: (process.env.NODE_ENV as AppConfig['nodeEnv']) || 'development',
  };
}
export const config: AppConfig = loadConfig();
console.log(`Starting in ${config.nodeEnv} mode on port ${config.port}`);
